  `analyzed_entity_id` int NOT NULL COMMENT 'The ID of the analyzed entity',
  `analysis_version` int NOT NULL COMMENT 'The version of the analysis that was performed',
  `analyzed_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT 'The timestamp of when the analysis was performed',
  `result` bit(1) NOT NULL COMMENT 'The result of the analysis - true for passed, false for failed',
  `stale` bit(1) NOT NULL DEFAULT b'0' COMMENT 'True when the entity needs re-analysis due to upstream changes',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_unique_analysis_finding` (`analyzed_entity_type`,`analyzed_entity_id`),
  KEY `idx_analyzed_entity` (`analyzed_entity_type`,`analyzed_entity_id`),
  KEY `idx_analysis_result` (`result`),
  KEY `idx_analysis_finding_stale` (`stale`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Findings from analysis of cards, transforms, dashboards, etc.';
