INSERT INTO `revision` VALUES (1,'Card',40,13371339,'2026-04-23 22:18:05.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":2,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Utilisateurs par role\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":2,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(r.role, \'SANS_ROLE\') AS role,\\n  COUNT(*) AS total\\nFROM users u\\nLEFT JOIN roles r ON r.role_id = u.role_id\\nGROUP BY COALESCE(r.role, \'SANS_ROLE\')\\nORDER BY total DESC;\"}]},\"parameter_mappings\":[],\"display\":\"pie\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(2,'Card',41,13371339,'2026-04-23 22:18:05.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":2,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Inscriptions par mois\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":2,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  DATE_FORMAT(COALESCE(u.date_of_birth, CURRENT_DATE), \'%Y-%m\') AS mois,\\n  COUNT(*) AS inscriptions\\nFROM users u\\nGROUP BY DATE_FORMAT(COALESCE(u.date_of_birth, CURRENT_DATE), \'%Y-%m\')\\nORDER BY mois ASC;\"}]},\"parameter_mappings\":[],\"display\":\"line\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(3,'Card',42,13371339,'2026-04-23 22:18:05.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":3,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Top 10 competences CV\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":3,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(\\n    NULLIF(TRIM(c.language_programmation), \'\'),\\n    NULLIF(TRIM(c.framework), \'\'),\\n    NULLIF(TRIM(c.bibliotheque), \'\'),\\n    NULLIF(TRIM(c.api), \'\'),\\n    NULLIF(TRIM(c.db), \'\'),\\n    NULLIF(TRIM(c.system_exploitation), \'\'),\\n    NULLIF(TRIM(c.conception), \'\'),\\n    NULLIF(TRIM(c.methodologie), \'\'),\\n    NULLIF(TRIM(c.design_pattern), \'\'),\\n    NULLIF(TRIM(c.architechture), \'\'),\\n    NULLIF(TRIM(c.outils), \'\'),\\n    CONCAT(\'COMP_\', c.id_competence)\\n  ) AS skill_name,\\n  COUNT(*) AS frequency\\nFROM cv_competence cc\\nLEFT JOIN competence c ON c.id_competence = cc.competence_id\\nGROUP BY skill_name\\nORDER BY frequency DESC\\nLIMIT 10;\"}]},\"parameter_mappings\":[],\"display\":\"bar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(4,'Card',43,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":4,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Missions par statut\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":4,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(m.status_mission, \'INCONNU\') AS statut,\\n  COUNT(*) AS total\\nFROM mission m\\nGROUP BY COALESCE(m.status_mission, \'INCONNU\')\\nORDER BY total DESC;\"}]},\"parameter_mappings\":[],\"display\":\"pie\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(5,'Card',44,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":4,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Candidatures par mission (Top 10)\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":4,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(dm.mission_name, CONCAT(\'Mission #\', m.id_mission)) AS titre,\\n  COUNT(c.id_candidature) AS nb_candidatures\\nFROM mission m\\nLEFT JOIN candidature c ON c.mission_id = m.id_mission\\nLEFT JOIN descrip_mission dm ON dm.id_mission = m.id_mission\\nGROUP BY m.id_mission, dm.mission_name\\nORDER BY nb_candidatures DESC\\nLIMIT 10;\"}]},\"parameter_mappings\":[],\"display\":\"bar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(6,'Card',45,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":4,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Taux de conversion candidatures\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":4,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COUNT(*) AS total_candidatures,\\n  SUM(CASE WHEN COALESCE(statut_candidature, \'ENCOURS\') = \'ACCEPTER\' THEN 1 ELSE 0 END) AS acceptees,\\n  ROUND(\\n    100.0 * SUM(CASE WHEN COALESCE(statut_candidature, \'ENCOURS\') = \'ACCEPTER\' THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0),\\n    2\\n  ) AS taux_conversion\\nFROM candidature;\"}]},\"parameter_mappings\":[],\"display\":\"scalar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(7,'Card',46,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":4,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Evolution candidatures par mois\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":4,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  DATE_FORMAT(COALESCE(date_postulation, CURRENT_DATE), \'%Y-%m\') AS mois,\\n  COUNT(*) AS total\\nFROM candidature\\nGROUP BY DATE_FORMAT(COALESCE(date_postulation, CURRENT_DATE), \'%Y-%m\')\\nORDER BY mois ASC;\"}]},\"parameter_mappings\":[],\"display\":\"line\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(8,'Card',47,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":5,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Score moyen par quiz\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":5,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  \'Quiz global\' AS titre,\\n  ROUND(AVG(COALESCE(uqr.score, 0)), 2) AS score_moyen,\\n  COUNT(uqr.id) AS nb_passages\\nFROM user_quiz_results uqr;\"}]},\"parameter_mappings\":[],\"display\":\"bar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(9,'Card',48,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":5,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Taux de reussite quiz\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":5,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  \'Quiz global\' AS titre,\\n  COUNT(uqr.id) AS total_passages,\\n  SUM(CASE WHEN COALESCE(uqr.passed, 0) = 1 THEN 1 ELSE 0 END) AS reussis,\\n  ROUND(\\n    100.0 * SUM(CASE WHEN COALESCE(uqr.passed, 0) = 1 THEN 1 ELSE 0 END) / NULLIF(COUNT(uqr.id), 0),\\n    2\\n  ) AS taux_reussite\\nFROM user_quiz_results uqr;\"}]},\"parameter_mappings\":[],\"display\":\"table\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(10,'Card',49,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":6,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Score moyen CodingGame par defi\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":6,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(f.name, CONCAT(\'Framework #\', f.id)) AS title,\\n  ROUND(AVG(COALESCE(er.score, 0)), 2) AS score_moyen,\\n  COUNT(er.id) AS nb_tentatives\\nFROM framework f\\nLEFT JOIN evaluation_result er ON er.framework_id = f.id\\nGROUP BY f.id, f.name\\nORDER BY score_moyen DESC;\"}]},\"parameter_mappings\":[],\"display\":\"bar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(11,'Card',50,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":6,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Taux de completion defis CodingGame\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":6,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  COALESCE(f.name, CONCAT(\'Framework #\', f.id)) AS title,\\n  COUNT(es.id) AS tentatives,\\n  SUM(CASE WHEN es.end_time IS NOT NULL THEN 1 ELSE 0 END) AS completes,\\n  ROUND(\\n    100.0 * SUM(CASE WHEN es.end_time IS NOT NULL THEN 1 ELSE 0 END) / NULLIF(COUNT(es.id), 0),\\n    2\\n  ) AS taux_completion\\nFROM framework f\\nLEFT JOIN evaluation_result er ON er.framework_id = f.id\\nLEFT JOIN evaluation_session es ON es.id = er.session_id\\nGROUP BY f.id, f.name;\"}]},\"parameter_mappings\":[],\"display\":\"table\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(12,'Card',51,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Question generee automatiquement pour le pilotage BI Find-Me.\",\"archived\":false,\"collection_position\":null,\"source_card_id\":null,\"table_id\":null,\"embedding_type\":null,\"card_schema\":23,\"database_id\":2,\"enable_embedding\":false,\"collection_id\":5,\"query_type\":\"native\",\"name\":\"Vue globale KPIs\",\"type\":\"question\",\"embedding_params\":null,\"cache_ttl\":null,\"dataset_query\":{\"lib/type\":\"mbql/query\",\"database\":2,\"stages\":[{\"lib/type\":\"mbql.stage/native\",\"native\":\"SELECT\\n  (SELECT COUNT(*) FROM users) AS total_users,\\n  (SELECT COUNT(*) FROM users u LEFT JOIN roles r ON r.role_id = u.role_id WHERE COALESCE(r.role, \'\') = \'CANDIDAT\') AS candidats,\\n  (SELECT COUNT(*) FROM users u LEFT JOIN roles r ON r.role_id = u.role_id WHERE COALESCE(r.role, \'\') IN (\'ESN_ADMIN\', \'ESN_COMMARCIAL\', \'CHARGEDERECRUTEMENT\', \'INTERCONTRAT\')) AS recruteurs;\"}]},\"parameter_mappings\":[],\"display\":\"scalar\",\"archived_directly\":false,\"collection_preview\":true,\"visualization_settings\":{},\"parameters\":[],\"dashboard_id\":null}',_binary '\0',_binary '',NULL,_binary '','v0.60.2.4 (f0b7139)'),(13,'Dashboard',2,13371339,'2026-04-23 22:18:06.000000','{\"description\":\"Dashboard BI global